arguments.command:
cat > /tmp/stackalloc_nint.cs << 'EOF'
Span<nint> span = stackalloc nint[5];
for (int i = 0; i < span.Length; i++)
    span[i] = (nint)(i * 10);

Console.WriteLine($"Span<nint> length: {span.Length}, sizeof(nint): {sizeof(nint)}");
for (int i = 0; i < span.Length; i++)
    Console.WriteLine($"  span[{i}] = {span[i]}");

// Also test nuint
Span<nuint> uspan = stackalloc nuint[3];
uspan[0] = 42;
uspan[1] = nuint.MaxValue;
uspan[2] = 0;
Console.WriteLine($"\nSpan<nuint> length: {uspan.Length}, sizeof(nuint): {sizeof(nuint)}");
for (int i = 0; i < uspan.Length; i++)
    Console.WriteLine($"  uspan[{i}] = {uspan[i]}");
EOF
